    # Step 3: Calculate novelty factor (preference for less visited nodes).
    novelty_factors = {node: 1.0 / (visit_frequencies[node] + 1.e-5) for node in unvisited_nodes}

    # Step 4: Compute a combined utility score.
    combined_scores = {node: inverse_distance_scores[node] * 0.7 + novelty_factors[node] * 0.3 for node in unvisited_nodes}

